#!/usr/bin/env ruby
# frozen_string_literal: true

require 'base64'
require 'json'
require 'stringio'

module SinatraCompat
  ROUTE_PARAM_REGEX = /:([A-Za-z_][A-Za-z0-9_]*)/.freeze
  JSON_MIME_TYPE = 'application/json; charset=utf-8'

  class << self
    attr_accessor :current_request

    def reset!
      @default_app = App.new
      @registered_apps = []
      @current_request = nil
    end

    def default_app
      @default_app ||= App.new
    end

    def registered_apps
      @registered_apps ||= []
    end

    def register_app(app)
      registered_apps << app
      app
    end

    def active_app
      registered_apps.last || default_app
    end

    def install!
      return if @installed

      reset!
      install_sinatra_constants
      install_kernel_dsl
      @installed = true
    end

    def dispatch(request_envelope)
      active_app.dispatch(request_envelope)
    end

    private

    def install_sinatra_constants
      Object.send(:remove_const, :Sinatra) if Object.const_defined?(:Sinatra)
      sinatra_module = Module.new
      Object.const_set(:Sinatra, sinatra_module)

      sinatra_module.const_set(:Base, Class.new do
        class << self
          def inherited(subclass)
            super
            subclass.instance_variable_set(:@compat_app, SinatraCompat::App.new)
            SinatraCompat.register_app(subclass.compat_app)
          end

          def compat_app
            @compat_app ||= SinatraCompat::App.new
          end

          def route(method, path, &block)
            compat_app.route(method, path, &block)
          end

          def before(path = nil, &block)
            compat_app.before(path, &block)
          end

          def set(key, value)
            compat_app.set(key, value)
          end

          def run!(*)
            nil
          end

          %i[get post put delete patch head options].each do |verb|
            define_method(verb) do |path = nil, &block|
              route(verb.to_s.upcase, path, &block)
            end
          end
        end
      end)
    end

    def install_kernel_dsl
      return if Kernel.private_method_defined?(:__xgnosis_sinatra_require)

      Kernel.module_eval do
        alias_method :__xgnosis_sinatra_require, :require

        define_method(:require) do |name|
          if name == 'sinatra' || name == 'sinatra/base'
            SinatraCompat.install!
            true
          else
            __xgnosis_sinatra_require(name)
          end
        end

        define_method(:request) do
          SinatraCompat.current_request or raise 'Sinatra request is only available during compatibility execution'
        end

        define_method(:params) do
          request.params
        end

        define_method(:set) do |key, value|
          SinatraCompat.default_app.set(key, value)
        end

        define_method(:before) do |path = nil, &block|
          SinatraCompat.default_app.before(path, &block)
        end

        %i[get post put delete patch head options].each do |verb|
          define_method(verb) do |path = nil, &block|
            SinatraCompat.default_app.route(verb.to_s.upcase, path, &block)
          end
        end
      end
    end
  end

  class RequestState
    attr_reader :body, :headers, :params, :path_info, :query_string, :request_method

    def initialize(request_envelope, route_params)
      serialized_body = request_envelope.fetch('body', nil)
      raw_body = if serialized_body.is_a?(Hash) && serialized_body['encoding'] == 'base64'
                   Base64.decode64(serialized_body['value'].to_s)
                 else
                   ''.b
                 end

      @request_method = request_envelope.fetch('method', 'GET').to_s.upcase
      @path_info = request_envelope.fetch('path', '/').to_s
      @query_string = request_envelope.fetch('query', '').to_s.sub(/\A\?/, '')
      @headers = normalize_headers(request_envelope.fetch('headers', {}))
      @body = StringIO.new(raw_body)
      @params = parse_query(@query_string).merge(route_params)
    end

    private

    def normalize_headers(input)
      input.each_with_object({}) do |(key, value), headers|
        headers[key.to_s.downcase] = value
      end
    end

    def parse_query(query)
      return {} if query.nil? || query.empty?

      query.split('&').each_with_object({}) do |pair, params|
        key, value = pair.split('=', 2)
        next if key.nil? || key.empty?

        params[decode_component(key)] = decode_component(value.to_s)
      end
    end

    def decode_component(value)
      value.tr('+', ' ')
    end
  end

  class Context
    attr_reader :request, :response_headers

    def initialize(request_state)
      @request = request_state
      @response_status = 200
      @response_headers = {}
      @response_body = nil
    end

    def params
      request.params
    end

    def status(value = nil)
      return @response_status if value.nil?

      @response_status = Integer(value)
    end

    def headers(values = nil)
      return @response_headers if values.nil?

      @response_headers.merge!(values)
    end

    def content_type(value = nil)
      return @response_headers['Content-Type'] if value.nil?

      @response_headers['Content-Type'] =
        case value
        when :json then JSON_MIME_TYPE
        when Symbol then value.to_s
        else value.to_s
        end
    end

    def body(value = nil)
      return @response_body if value.nil?

      @response_body = value
    end

    def finalize(result)
      status, headers, body = normalize_result(result)
      {
        'matched' => true,
        'response' => {
          'status' => status,
          'headers' => headers,
          'body' => {
            'encoding' => 'base64',
            'value' => Base64.strict_encode64(body)
          }
        }
      }
    end

    private

    def normalize_result(result)
      current_headers = @response_headers.dup
      current_status = @response_status
      current_body = @response_body

      if result.is_a?(Array) && result.length == 3 && result[0].is_a?(Integer)
        current_status = result[0]
        current_headers.merge!(result[1].is_a?(Hash) ? result[1] : {})
        current_body = normalize_body(result[2])
      elsif result.is_a?(Array) && result.length == 3
        current_body = normalize_body(result[0])
        current_status = Integer(result[1])
        current_headers.merge!(result[2].is_a?(Hash) ? result[2] : {})
      elsif result.is_a?(Array) && result.length == 2
        current_body = normalize_body(result[0])
        if result[1].is_a?(Hash)
          current_headers.merge!(result[1])
        else
          current_status = Integer(result[1])
        end
      elsif !result.nil?
        current_body = normalize_body(result)
      elsif current_body.nil?
        current_body = ''.b
      else
        current_body = normalize_body(current_body)
      end

      [current_status, current_headers, current_body]
    end

    def normalize_body(value)
      case value
      when nil then ''.b
      when String then value.b
      when Array then value.map { |chunk| normalize_body(chunk) }.join
      else value.to_s.b
      end
    end
  end

  class App
    def initialize
      @routes = []
      @before_filters = []
      @settings = {}
    end

    def route(method, path, &block)
      @routes << Route.new(method, path, block)
    end

    def before(path = nil, &block)
      @before_filters << [path, block]
    end

    def set(key, value)
      @settings[key.to_sym] = value
    end

    def dispatch(request_envelope)
      route, route_params = match_route(
        request_envelope.fetch('method', 'GET'),
        request_envelope.fetch('path', '/')
      )
      return { 'matched' => false } if route.nil?

      request_state = RequestState.new(request_envelope, route_params)
      context = Context.new(request_state)
      SinatraCompat.current_request = request_state

      begin
        @before_filters.each do |path, filter|
          next unless path.nil? || request_state.path_info.start_with?(path)

          context.instance_exec(&filter)
        end

        result = context.instance_exec(&route.block)
        context.finalize(result)
      ensure
        SinatraCompat.current_request = nil
      end
    end

    private

    def match_route(method, path)
      @routes.each do |route|
        matched = route.match(method, path)
        return [route, matched] unless matched.nil?
      end

      [nil, nil]
    end
  end

  class Route
    attr_reader :block

    def initialize(method, path, block)
      @method = method.to_s.upcase
      @path = path.to_s
      @block = block
      @pattern = compile_pattern(@path)
    end

    def match(method, path)
      return nil unless @method == method.to_s.upcase

      matched = @pattern.match(path.to_s)
      return nil if matched.nil?

      matched.named_captures
    end

    private

    def compile_pattern(path)
      escaped = Regexp.escape(path)
      pattern = escaped.gsub(Regexp.escape(':')) do
        ':'
      end
      pattern = pattern.gsub(ROUTE_PARAM_REGEX) do
        "(?<#{Regexp.last_match(1)}>[^/]+)"
      end
      /\A#{pattern}\z/
    end
  end
end

def execute_function(file_path, function_name, args)
  load(file_path)
  send(function_name.to_sym, *args)
end

def execute_compatibility(request)
  compatibility = request['compatibility']
  raise 'missing compatibility request' if compatibility.nil?
  raise "unsupported compatibility family #{compatibility['family'].inspect}" unless compatibility['family'] == 'ruby-service'
  raise "unsupported Ruby service framework #{compatibility['framework'].inspect}" unless compatibility['framework'] == 'sinatra'

  SinatraCompat.install!
  SinatraCompat.reset!
  load(request['filePath'].to_s)
  SinatraCompat.dispatch(compatibility['request'] || {})
end

begin
  raw_input = $stdin.read
  if raw_input.nil? || raw_input.strip.empty?
    puts JSON.generate({ status: 'error', value: 'empty input', stdout: '', stderr: '' })
    exit 0
  end

  request = JSON.parse(raw_input)

  if request['action'] == 'ping'
    puts JSON.generate({ status: 'ok', value: 'pong', stdout: '', stderr: '' })
    exit 0
  end

  file_path = request['filePath'] || ''
  function_name = request['functionName'] || 'main'
  args = request['args'] || []

  captured_stdout = StringIO.new
  captured_stderr = StringIO.new
  old_stdout = $stdout
  old_stderr = $stderr

  begin
    $stdout = captured_stdout
    $stderr = captured_stderr

    result = if request['compatibility']
               execute_compatibility(request)
             else
               execute_function(file_path, function_name, args)
             end

    $stdout = old_stdout
    $stderr = old_stderr

    value = begin
      JSON.generate(result)
      result
    rescue TypeError, JSON::GeneratorError
      result.to_s
    end

    puts JSON.generate({
      status: 'ok',
      value: value,
      stdout: captured_stdout.string,
      stderr: captured_stderr.string
    })
  rescue StandardError => e
    $stdout = old_stdout
    $stderr = old_stderr

    puts JSON.generate({
      status: 'error',
      value: "#{e.class}: #{e.message}\n#{e.backtrace&.first(8)&.join("\n")}",
      stdout: captured_stdout.string,
      stderr: captured_stderr.string
    })
  end
rescue StandardError => e
  puts JSON.generate({
    status: 'error',
    value: "harness error: #{e.message}",
    stdout: '',
    stderr: ''
  })
end
